<template><div class="page-container"><div class="page-header"><div><h1>{{ inbound ? '户口迁入申请' : '户口迁出申请' }}</h1><p>迁移先申请审批，批准后由授权经办人显式执行。</p></div><el-button v-if="canCreate" type="primary" :icon="Plus" @click="open">新建申请</el-button></div>
<el-card shadow="never"><el-table :data="rows" v-loading="loading" border><el-table-column prop="applicationNo" label="申请编号" min-width="190"/><el-table-column prop="title" label="标题" min-width="180"/><el-table-column prop="applicantName" label="申请人" width="110"/><el-table-column prop="status" label="状态" width="140"><template #default="{row}"><StatusTag :status="row.status"/></template></el-table-column><el-table-column prop="createdAt" label="创建时间" width="180"/><el-table-column label="操作" width="100"><template #default="{row}"><el-button link type="primary" @click="$router.push(`/migrations/applications/${row.applicationId}`)">详情</el-button></template></el-table-column></el-table><AppPagination v-model:current="page" v-model:size="size" :total="total" @change="load"/></el-card>
<FormDialog v-model:visible="visible" :title="inbound?'新建迁入申请':'新建迁出申请'" :loading="saving" @confirm="save"><el-form ref="formRef" :model="form" :rules="rules" label-width="120px"><el-form-item label="人员" prop="personId"><PersonSelect v-model="form.personId"/></el-form-item><el-form-item label="迁移类型" prop="migrationType"><el-select v-model="form.migrationType"><el-option label="外来/迁往市外" value="OUTSIDE_CITY"/><el-option label="同市跨区" value="IN_CITY_CROSS_DISTRICT"/></el-select></el-form-item><template v-if="inbound"><el-form-item label="来源区划"><el-input v-model="form.fromRegionCode"/></el-form-item><el-form-item label="来源地址" prop="fromAddress"><el-input v-model="form.fromAddress"/></el-form-item><el-form-item label="目标区划" prop="toRegionCode"><el-input v-model="form.toRegionCode"/></el-form-item><el-form-item label="目标家庭户" prop="toHouseholdId"><el-input-number v-model="form.toHouseholdId" :min="1"/></el-form-item><el-form-item v-if="form.migrationType==='IN_CITY_CROSS_DISTRICT'" label="迁移批次" prop="transferBatchNo"><el-input v-model="form.transferBatchNo" placeholder="TR-yyyyMMdd-xxxxxx"/></el-form-item><el-form-item label="迁入日期" prop="inDate"><el-date-picker v-model="form.inDate" value-format="YYYY-MM-DD"/></el-form-item></template><template v-else><el-alert type="info" :closable="false" title="原家庭户、原地址和区划由后端从当前户籍读取，不能手工填写。"/><el-form-item label="目标区划"><el-input v-model="form.toRegionCode"/></el-form-item><el-form-item label="目标地址" prop="toAddress"><el-input v-model="form.toAddress"/></el-form-item><el-form-item label="迁出日期" prop="outDate"><el-date-picker v-model="form.outDate" value-format="YYYY-MM-DD"/></el-form-item><el-form-item label="新户主人员ID"><el-input-number v-model="form.newHeadPersonId" :min="1" placeholder="户主迁出且仍有成员时填写"/></el-form-item></template><el-form-item label="标题" prop="title"><el-input v-model="form.title"/></el-form-item><el-form-item label="原因" prop="reason"><el-input v-model="form.reason" type="textarea"/></el-form-item><el-form-item label="备注"><el-input v-model="form.remark"/></el-form-item></el-form></FormDialog></div></template>
<script setup>
import {computed,onMounted,reactive,ref,watch} from 'vue';import {useRoute,useRouter} from 'vue-router';import {Plus} from '@element-plus/icons-vue';import {ElMessage} from 'element-plus';import {listApplications} from '../../api/applications';import {createMigrationIn,createMigrationOut} from '../../api/migrations';import {useUserStore} from '../../stores/user';import PersonSelect from '../../components/business/PersonSelect.vue';import FormDialog from '../../components/common/FormDialog.vue';import AppPagination from '../../components/common/AppPagination.vue';import StatusTag from '../../components/common/StatusTag.vue';
const route=useRoute(),router=useRouter(),user=useUserStore();const inbound=computed(()=>route.meta.type==='in');const canCreate=computed(()=>user.hasPermission(inbound.value?'migration:in:create':'migration:out:create'));const rows=ref([]),loading=ref(false),page=ref(1),size=ref(10),total=ref(0),visible=ref(false),saving=ref(false),formRef=ref();const blank=()=>({personId:null,migrationType:'OUTSIDE_CITY',fromRegionCode:'',fromAddress:'',toRegionCode:'',toHouseholdId:null,transferBatchNo:'',inDate:'',toAddress:'',outDate:'',newHeadPersonId:null,title:'',reason:'',remark:''});const form=reactive(blank());const rules={personId:[{required:true,message:'请选择人员'}],migrationType:[{required:true}],fromAddress:[{required:true,message:'请输入来源地址'}],toRegionCode:[{required:true,message:'请输入目标区划'}],toHouseholdId:[{required:true,message:'请选择目标家庭户'}],inDate:[{required:true,message:'请选择日期'}],toAddress:[{required:true,message:'请输入目标地址'}],outDate:[{required:true,message:'请选择日期'}],title:[{required:true,message:'请输入标题'}],reason:[{required:true,message:'请输入原因'}],transferBatchNo:[{validator:(_,v,cb)=>form.migrationType==='IN_CITY_CROSS_DISTRICT'&&!v?cb(new Error('跨区迁入必须填写批次')):cb()}]};
async function load(){loading.value=true;try{const r=await listApplications({businessType:inbound.value?'MIGRATION_IN':'MIGRATION_OUT',page:page.value-1,size:size.value});rows.value=r.content||[];total.value=r.totalElements||0}finally{loading.value=false}}function open(){Object.assign(form,blank());visible.value=true}async function save(){await formRef.value.validate();saving.value=true;try{const result=await (inbound.value?createMigrationIn(form):createMigrationOut(form));ElMessage.success('迁移申请草稿已创建');visible.value=false;router.push(`/migrations/applications/${result.applicationId}`)}finally{saving.value=false}}watch(inbound,()=>{page.value=1;load()});onMounted(load);
</script><style scoped>.page-container{display:flex;flex-direction:column;gap:16px}.page-header{display:flex;justify-content:space-between;align-items:flex-end}.page-header h1{margin:0}.page-header p{color:#64748b;margin:8px 0 0}</style>
